codeExamples.typescript:
import axios from 'axios';

(async () => {
  const baseUrl = 'http://localhost:3010';
  const path = '/auth/connection-tokens';
  const url = `${baseUrl}${path}`;

  const response = await axios({
    method: 'post',
    headers: {
      'Authorization': 'Bearer 288adad9312ec64eff74b5bb706b29916ee70d053366d1def53f90cf74ff55cc'
    },
    url
  });
  const data = response.data;
  console.log(data);
})();

codeExamples.javascript:
const baseUrl = 'http://localhost:3010';
const path = '/auth/pair';
const url = `${baseUrl}${path}`;

const response = await fetch(url, {
  method: 'POST',
  headers: {
    'Content-Type': 'application/json'
  },
  body: JSON.stringify({
      "code": "JEWWK7",
      "worldId": "test-world-integration",
      "worldTitle": "Test World"
    })
});
const data = await response.json();
console.log(data);

codeExamples.typescript:
import axios from 'axios';

(async () => {
  const baseUrl = 'http://localhost:3010';
  const path = '/auth/pair';
  const url = `${baseUrl}${path}`;

  const response = await axios({
    method: 'post',
    headers: {
      'Content-Type': 'application/json'
    },
    url,
    data: {
        "code": "JEWWK7",
        "worldId": "test-world-integration",
        "worldTitle": "Test World"
      }
  });
  const data = response.data;
  console.log(data);
})();
